const raw = $input.first().json.body || $input.first().json;
const binary = $input.first().binary || {};

let body = raw;
if (typeof raw.payload === 'string') {
  try {
    body = JSON.parse(raw.payload);
  } catch (error) {
    throw new Error('Payload konnte nicht als JSON gelesen werden');
  }
}

function formatDatum(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return yyyy + '-' + mm + '-' + dd;
}

function clean(value) {
  return String(value || '').trim();
}

const thema = clean(body.Thema || body.Title || body.thema);
if (!thema) throw new Error('Pflichtfeld Thema fehlt');

const personenSichtbar = clean(body.Personen_sichtbar || 'nein').toLowerCase();
const einverstaendnis = clean(body.Einverstaendnis_vorhanden || 'nein').toLowerCase();
if (personenSichtbar === 'ja' && einverstaendnis !== 'ja') {
  throw new Error('DSGVO-Sperre: Personen sichtbar, aber Einverstaendnis fehlt');
}

const postTyp = clean(body.Post_Typ || body.postTyp || 'Standard');
const videoTypes = ['Reel', 'Story', 'Übung', 'Uebung'];
const fotoQuelle = clean(body.Foto_Quelle || 'none').toLowerCase();
let materialTyp = clean(body.Material_Typ || '').toLowerCase();
if (!materialTyp) {
  materialTyp = fotoQuelle === 'video' ? 'video' : fotoQuelle === 'upload' ? 'foto' : fotoQuelle === 'stock' ? 'stock' : 'kein_upload';
}

const hasFotoBinary = Boolean(binary.foto || binary.Foto_Upload || (materialTyp !== 'video' && binary.data));
const hasVideoBinary = Boolean(binary.video || binary.Video_Upload || (materialTyp === 'video' && binary.data));

if (materialTyp === 'foto' && !hasFotoBinary) {
  throw new Error('Material_Typ=foto, aber kein Foto-Binary empfangen');
}
if (materialTyp === 'video' && !hasVideoBinary) {
  throw new Error('Material_Typ=video, aber kein Video-Binary empfangen');
}
if (videoTypes.includes(postTyp) && materialTyp !== 'video') {
  throw new Error('Post_Typ ist Video/Reel/Story/Uebung, aber Material_Typ ist nicht video');
}

const brief     = clean(body.Content_Brief || body.textIdee);
const datum     = formatDatum(body.Veroeffentlichungsdatum || body.wunschDatum || '');
const uhrzeit   = clean(body.Uhrzeit || body.uhrzeit);
const hashtag   = clean(body.Hashtag_Thema || body.hashtag);
const bild      = clean(body.Bild_Dateiname || body.bildBeschreibung);
const freigabe  = clean(body.Freigabe_Person || 'Judith');
const kommentar = clean(body.Kommentare || body.notiz);
const videoHinweis = clean(body.Video_Hinweis);
const tonSprache = clean(body.Ton_enthaelt_Sprache || 'unbekannt').toLowerCase();

// NEU: Sofort-Posten Flag aus Formular-Checkbox
const sofortPosten = body.Sofort_Posten === true || body.Sofort_Posten === 'true';

const status = materialTyp === 'video' ? 'Video eingegangen' : 'Entwurf';
const workflowZiel = materialTyp === 'video' ? 'video-reel-story' : 'foto-feed-post';

const materialMeta = [
  'WF-01 v4 Material-Input:',
  '- Workflow-Ziel: ' + workflowZiel,
  '- Material-Typ: ' + materialTyp,
  '- Foto-Quelle: ' + fotoQuelle,
  body.Foto_Motiv ? '- Motiv: ' + clean(body.Foto_Motiv) : null,
  videoHinweis ? '- Video-Hinweis: ' + videoHinweis : null,
  materialTyp === 'video' ? '- Ton enthaelt Sprache: ' + tonSprache : null,
  '- Personen sichtbar: ' + personenSichtbar,
  '- Einverstaendnis vorhanden: ' + einverstaendnis,
  body.Zuschnitt_Hinweis ? '- Zuschnitt: ' + clean(body.Zuschnitt_Hinweis) : null,
  sofortPosten ? '- 🚀 SOFORT-POSTEN aktiviert (Karenz + Datum werden in WF-03 übersprungen)' : null,
].filter(Boolean).join('\n');

return [{
  json: {
    Title: thema,
    field_1: thema,
    field_2: postTyp,
    field_3: brief,
    field_5: uhrzeit,
    field_6: status,
    field_7: hashtag,
    field_8: bild,
    field_11: freigabe,
    field_13: [kommentar, materialMeta].filter(Boolean).join('\n\n'),
    Ver_x00f6_ffentlichungsdatum: datum,
    Sofort_Posten: sofortPosten,
    _eingereichtVon: body._eingereichtVon || 'Judith',
    _eingereichtAm: body._eingereichtAm || new Date().toISOString(),
    _workflow_ziel: workflowZiel,
    _postTyp: postTyp,
    _datum: datum,
    _material_typ: materialTyp,
    _foto_quelle: fotoQuelle,
    _foto_motiv: clean(body.Foto_Motiv),
    _video_hinweis: videoHinweis,
    _ton_enthaelt_sprache: tonSprache,
    _personen_sichtbar: personenSichtbar,
    _einverstaendnis_vorhanden: einverstaendnis,
    _zuschnitt_hinweis: clean(body.Zuschnitt_Hinweis),
    _sofort_posten: sofortPosten,
    _has_foto_binary: hasFotoBinary,
    _has_video_binary: hasVideoBinary,
  },
  binary,
}];

const created = $('SharePoint: Item erstellen').first().json;
const mapped = $('Felder mappen').first();
const data = mapped.json;
const binary = mapped.binary || {};

const itemIdRaw = created.id || created.fields?.id || created.Ausweis || created.ID;
const itemId = String(itemIdRaw || '').padStart(3, '0');
const datumRaw = data.Ver_x00f6_ffentlichungsdatum || data._datum;
const year = datumRaw ? new Date(datumRaw).getFullYear() : new Date().getFullYear();

function slugify(value) {
  return String(value || 'post')
    .toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss')
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .replace(/_+/g, '_')
    .slice(0, 40) || 'post';
}

const fotoBinary = binary.foto || binary.Foto_Upload || (data._material_typ !== 'video' ? binary.data : undefined);
const videoBinary = binary.video || binary.Video_Upload || (data._material_typ === 'video' ? binary.data : undefined);
const slug = slugify(data._foto_motiv || data.field_1);

const fotoOriginalName = fotoBinary?.fileName || 'foto.jpg';
const fotoExtMatch = fotoOriginalName.toLowerCase().match(/\.(jpe?g|png|webp)$/);
const fotoExt = fotoExtMatch ? fotoExtMatch[1].replace('jpeg', 'jpg') : 'jpg';
const photoFilename = data._material_typ === 'foto' ? `PF_${year}_${itemId}_${slug}.${fotoExt}` : '';

const videoOriginalName = videoBinary?.fileName || 'video.mp4';
const videoExtMatch = videoOriginalName.toLowerCase().match(/\.(mp4|mov)$/);
const videoExt = videoExtMatch ? videoExtMatch[1] : 'mp4';
const videoFilename = data._material_typ === 'video' ? `PF_${year}_${itemId}_${slug}_raw.${videoExt}` : '';
const projectFolder = data._material_typ === 'video'
  ? `${year}-${String(new Date(datumRaw || Date.now()).getMonth() + 1).padStart(2, '0')}-${String(new Date(datumRaw || Date.now()).getDate()).padStart(2, '0')}_PF-${year}-${itemId}_${slug}`
  : '';

const SP_SITE = 'https://physiofuchs889.sharepoint.com/sites/PhysioFuchsTW';
const fotoFolderRel = `/sites/PhysioFuchsTW/Freigegebene Dokumente/Socialmedia/Content_Socialmedia/Fotos/${year}`;
const videoFolderRel = projectFolder
  ? `/sites/PhysioFuchsTW/Freigegebene Dokumente/Socialmedia/Content_Socialmedia/Reels_Stories/${projectFolder}/01_Rohmaterial`
  : '';

function uploadUrl(folderRel, filename) {
  if (!folderRel || !filename) return '';
  const safeFolder = folderRel.replace(/'/g, "''");
  const safeFilename = filename.replace(/'/g, "''");
  return `${SP_SITE}/_api/web/GetFolderByServerRelativeUrl('${safeFolder}')/Files/add(url='${safeFilename}',overwrite=false)`;
}

return [{
  json: {
    ...data,
    _sp_item_id: itemIdRaw,
    photo_should_upload: data._material_typ === 'foto' && Boolean(fotoBinary),
    video_should_upload: data._material_typ === 'video' && Boolean(videoBinary),
    photo_filename: photoFilename,
    video_filename: videoFilename,
    video_project_folder: projectFolder,
    photo_year: year,
    photo_folder_rel: fotoFolderRel,
    video_folder_rel: videoFolderRel,
    photo_upload_url: uploadUrl(fotoFolderRel, photoFilename),
    video_upload_url: uploadUrl(videoFolderRel, videoFilename),
  },
  binary: {
    ...(fotoBinary ? { foto: fotoBinary } : {}),
    ...(videoBinary ? { video: videoBinary } : {}),
  },
}];

const foto = $('Code: Material-Dateinamen bauen').first().json;
const mapped = $('Felder mappen').first().json;
const upload = $input.first().json || {};
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
const statusCode = upload.statusCode || upload.status || 200;
const uploadOk = statusCode < 400 && !upload.error;
const logLine = uploadOk
  ? `${now} WF-01 v4: Foto-Upload gespeichert als ${foto.photo_filename}`
  : `${now} WF-01 v4: Foto-Upload pruefen - Response ${statusCode}`;

return [{
  json: {
    _sp_item_id: foto._sp_item_id,
    photo_filename: foto.photo_filename,
    payload: {
      field_8: foto.photo_filename,
      field_13: [mapped.field_13 || '', logLine].filter(Boolean).join('\n')
    }
  }
}];

const material = $('Code: Material-Dateinamen bauen').first().json;
const mapped = $('Felder mappen').first().json;
const upload = $input.first().json || {};
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
const statusCode = upload.statusCode || upload.status || 200;
const uploadOk = statusCode < 400 && !upload.error;
const logLine = uploadOk
  ? `${now} WF-01 v4: Video-Upload gespeichert als ${material.video_filename} im Projekt ${material.video_project_folder}`
  : `${now} WF-01 v4: Video-Upload pruefen - Response ${statusCode}`;

return [{
  json: {
    _sp_item_id: material._sp_item_id,
    video_filename: material.video_filename,
    video_project_folder: material.video_project_folder,
    payload: {
      field_6: 'Video eingegangen',
      field_8: material.video_filename,
      field_13: [mapped.field_13 || '', logLine].filter(Boolean).join('\n')
    }
  }
}];
